{
  "sentences": [
    {
      "text": "我沒有去過臺北的故宮。",
      "pinyin": "Wǒ méiyǒu qù guò Táiběi de Gùgōng.",
      "pinyin_numeric": "wo3 mei2you3 qu4 guo4 Tai2bei3 de5 Gu4gong1.",
      "translation_en": "I have never been to the National Palace Museum in Taipei.",
      "translation_ko": "저는 타이베이의 고궁에 가 본 적이 없습니다."
    },
    {
      "text": "他從來沒有吃過滷肉飯。",
      "pinyin": "Tā cónglái méiyǒu chī guò lǔròufàn.",
      "pinyin_numeric": "ta1 cong2lai2 mei2you3 chi1 guo4 lu3rou4fan4.",
      "translation_en": "He has never eaten braised pork rice.",
      "translation_ko": "그는 루로우판을 먹어 본 적이 전혀 없습니다."
    },
    {
      "text": "我們沒有喝過珍珠奶茶嗎？",
      "pinyin": "Wǒmen méiyǒu hē guò zhēnzhū nǎichá ma?",
      "pinyin_numeric": "wo3men5 mei2you3 he1 guo4 zhen1zhu1 nai3cha2 ma0?",
      "translation_en": "Haven't we ever had bubble tea?",
      "translation_ko": "우리는 버블티를 마셔 본 적이 없나요?"
    },
    {
      "text": "我沒有看過九份的風景。",
      "pinyin": "Wǒ méiyǒu kàn guò Jiǔfèn de fēngjǐng.",
      "pinyin_numeric": "wo3 mei2you3 kan4 guo4 Jiu3fen4 de5 feng1jing3.",
      "translation_en": "I have never seen the scenery of Jiufen.",
      "translation_ko": "저는 주펀의 풍경을 본 적이 없습니다."
    },
    {
      "text": "她從來沒有去過國外旅行。",
      "pinyin": "Tā cónglái méiyǒu qù guò guówài lǚxíng.",
      "pinyin_numeric": "ta1 cong2lai2 mei2you3 qu4 guo4 guo2wai4 lü3xing2.",
      "translation_en": "She has never traveled abroad.",
      "translation_ko": "그녀는 해외 여행을 가 본 적이 전혀 없습니다."
    },
    {
      "text": "你沒有吃過臺南的小吃嗎？",
      "pinyin": "Nǐ méiyǒu chī guò Táinán de xiǎochī ma?",
      "pinyin_numeric": "ni3 mei2you3 chi1 guo4 Tai2nan2 de5 xiao3chi1 ma0?",
      "translation_en": "Haven't you ever eaten Tainan's street food?",
      "translation_ko": "타이난의 길거리 음식을 먹어 본 적이 없나요?"
    },
    {
      "text": "我沒有喝過高雄的紅茶。",
      "pinyin": "Wǒ méiyǒu hē guò Gāoxióng de hóngchá.",
      "pinyin_numeric": "wo3 mei2you3 he1 guo4 Gao1xiong2 de5 hong2cha2.",
      "translation_en": "I have never had Kaohsiung's black tea.",
      "translation_ko": "저는 가오슝의 홍차를 마셔 본 적이 없습니다."
    },
    {
      "text": "他從來沒有聽過這個故事。",
      "pinyin": "Tā cónglái méiyǒu tīng guò zhège gùshì.",
      "pinyin_numeric": "ta1 cong2lai2 mei2you3 ting1 guo4 zhe4ge5 gu4shi4.",
      "translation_en": "He has never heard this story before.",
      "translation_ko": "그는 이 이야기를 들어 본 적이 전혀 없습니다."
    },
    {
      "text": "我們沒有學過這個句子。",
      "pinyin": "Wǒmen méiyǒu xué guò zhège jùzi.",
      "pinyin_numeric": "wo3men5 mei2you3 xue2 guo4 zhe4ge5 ju4zi5.",
      "translation_en": "We have never studied this sentence.",
      "translation_ko": "우리는 이 문장을 배운 적이 없습니다."
    },
    {
      "text": "你從來沒有做過這個工作嗎？",
      "pinyin": "Nǐ cónglái méiyǒu zuò guò zhège gōngzuò ma?",
      "pinyin_numeric": "ni3 cong2lai2 mei2you3 zuo4 guo4 zhe4ge5 gong1zuo4 ma0?",
      "translation_en": "Have you never done this job before?",
      "translation_ko": "이 일을 해 본 적이 전혀 없나요?"
    }
  ]
}
